package com.shecancode.user.model; import jakarta.persistence.*; @Entity public class Address { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; private Long userId; private String province; private String district; private String sector; private String street; public Long getId(){return id;} public Long getUserId(){return userId;} public void setUserId(Long v){userId=v;} public String getProvince(){return province;} public void setProvince(String v){province=v;} public String getDistrict(){return district;} public void setDistrict(String v){district=v;} public String getSector(){return sector;} public void setSector(String v){sector=v;} public String getStreet(){return street;} public void setStreet(String v){street=v;} }